(function () {
  let _sOrient = null;
  let _sEl     = null;

  function _sEnterFs(el) {
    if (!el || document.fullscreenElement || document.webkitFullscreenElement) return;
    const req = el.requestFullscreen || el.webkitRequestFullscreen;
    if (req) req.call(el).catch(() => {});
  }

  function _sInit(el) {
    if (_sEl === el) return;
    _sEl = el;
    try { if (screen.orientation && screen.orientation.unlock) screen.orientation.unlock(); } catch(e) {}
    _sEnterFs(el);
    if (_sOrient) window.removeEventListener('resize', _sOrient);
    _sOrient = () => _sEnterFs(el);
    window.addEventListener('resize', _sOrient, { passive: true });
    if (window.attachQuickMenuTrigger) window.attachQuickMenuTrigger(el);
  }

  function _sDestroy() {
    if (_sOrient) { window.removeEventListener('resize', _sOrient); _sOrient = null; }
    _sEl = null;
    if (document.fullscreenElement || document.webkitFullscreenElement) {
      const exit = document.exitFullscreen || document.webkitExitFullscreen;
      if (exit) exit.call(document).catch(() => {});
    }
    try { if (screen.orientation && screen.orientation.lock) screen.orientation.lock('portrait').catch(() => {}); } catch(e) {}
  }

  function _patch() {
    const app = window._app;
    if (!app || !app.navigate || app.__sPatched) return;
    app.__sPatched = true;
    const _orig = app.navigate.bind(app);
    app.navigate = function (target) {
      _orig(target);
      if (target === 'learn' || target === 'synesthesia') {
        const c = document.querySelector('.synesthesia-wrapper');
        if (c) _sInit(c);
      } else if (_sEl) {
        _sDestroy();
      }
    };
  }

  if (window._app) { _patch(); }
  else { const t = setInterval(() => { if (window._app) { clearInterval(t); _patch(); } }, 50); }
})();
